window.addEventListener("load",()=>{const t=document.getElementById("projects-iframe");t?(t.src="projects-carousel.html",t.onload=function(){setTimeout(()=>{try{const e=t.contentDocument||t.contentWindow.document;t.style.height=e.body.scrollHeight+"px"}catch(e){t.style.height="800px",console.warn("Could not calculate iframe height, using fallback")}},500)}):console.warn("Projects iframe not found")});